// ============================================================
// CANADA RELEVANCE SCORING — CMCA Blog Automation
// Handles both English and French content (La Presse feeds)
// Score threshold: >= 0.3 to pass
// Updated: Mar 2026
// ============================================================

// +0.5: Canada is the primary subject (headline or lead paragraph)
const primaryCanadaSignals = [
  'canada', 'canadian', 'canadien', 'canadienne', 'canadiens', 'canadiennes',
  'cfib', 'fcei',
  'statistique canada', 'statistics canada',
  'banque du canada', 'bank of canada',
  'agence du revenu du canada', 'canada revenue agency', 'cra', 'arc',
  'gouvernement du canada', 'government of canada',
  'budget federal', 'federal budget', 'budget federale',
  'chambre des communes', 'house of commons',
  'economie canadienne', 'canadian economy',
  'pme canadienne', 'canadian sme'
];

// +0.3: Mentions Canadian companies/institutions
const canadianInstitutions = [
  'rbc', 'banque royale', 'td bank', 'banque td', 'bmo', 'banque de montreal',
  'scotiabank', 'banque scotia', 'cibc', 'banque nationale',
  'desjardins', 'caisse populaire', 'caisse desjardins',
  'shopify', 'loblaws', 'metro inc', 'sobeys', 'couche-tard',
  'bell canada', 'rogers', 'telus',
  'air canada', 'westjet',
  'bdc', 'banque de developpement du canada', 'business development bank',
  'edc', 'exportation et developpement canada',
  'investissement quebec',
  'pme', 'sme', 'petite entreprise', 'small business',
  'entrepreneur canadien', 'canadian entrepreneur',
  'chambre de commerce', 'chamber of commerce'
];

// +0.2: Mentions Canadian location
const canadianLocations = [
  'ontario', 'quebec', 'british columbia', 'colombie-britannique',
  'alberta', 'saskatchewan', 'manitoba', 'nouvelle-ecosse', 'nova scotia',
  'nouveau-brunswick', 'new brunswick', 'terre-neuve', 'newfoundland',
  'prince edward island', 'yukon', 'nunavut', 'northwest territories',
  'toronto', 'montreal', 'vancouver', 'calgary', 'edmonton',
  'ottawa', 'winnipeg', 'halifax', 'hamilton', 'kitchener', 'waterloo',
  'regina', 'saskatoon', 'victoria',
  'gta', 'greater toronto',
  'tps', 'tvq', 'tvh'
];

// -0.5: Focus is clearly another country
const foreignFocusSignals = [
  'wall street', 'federal reserve', 'the fed', 'us economy', 'u.s. economy',
  'american economy', 'white house', 'us congress', 'dow jones', 'nasdaq',
  's&p 500', 'sp500', 'european central bank', 'ecb', 'bank of england',
  'china economy', 'chinese economy', 'uk economy', 'british economy',
  'german economy', 'silicon valley', 'new york stock'
];

// -0.3: Global topic with no clear Canada angle (only if no positive signals)
const globalNoCanadaSignals = [
  'geopolitical', 'geopolitique', 'war fears', 'middle east conflict',
  'global recession', 'recession mondiale', 'worldwide inflation',
  'inflation mondiale', 'imf warns', 'fmi avertit', 'world bank warns',
  'davos', 'g20 summit', 'g7 summit'
];

// Hard exclusions — disqualifying regardless of score
const hardExclusions = [
  'investment portfolio', 'portefeuille d investissement',
  'wealth management', 'gestion de patrimoine',
  'crypto', 'cryptocurrency', 'cryptomonnaie',
  'bitcoin', 'ethereum', 'stablecoin', 'nft',
  'billionaire', 'milliardaire',
  'fixed income', 'revenu fixe',
  'family office',
  'etf', 'mutual fund', 'fonds commun',
  'hedge fund', 'fonds speculatif',
  'portfolio allocation', 'repartition du portefeuille',
  'high-net-worth',
  'pension fund', 'fonds de pension',
  'clo', 'leveraged loan', 'pret a effet de levier',
  'default rate',
  'dividend stocks', 'dividend-paying',
  'social media addiction',
  'workplace harassment', 'harcelement au travail',
  'freedom of speech', 'liberte d expression',
  'us supreme court', 'supreme court us',
  'hungary', 'orban',
  'war fears', 'crainte de guerre'
];

const SCORE_THRESHOLD = 0.3;

function scoreArticle(item) {
  const title = (item.json.title || '').toLowerCase();
  const content = (item.json.content || '').toLowerCase();
  const lead = content.substring(0, 500);
  const fullText = title + ' ' + content;

  let score = 0;
  const reasons = [];

  // Hard exclusion check first (fast exit)
  for (const term of hardExclusions) {
    const escaped = term.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const regex = new RegExp('\\b' + escaped + '\\b', 'i');
    if (regex.test(fullText)) {
      return { score: -99, reasons: ['EXCLUDED: "' + term + '"'], pass: false };
    }
  }

  // +0.5: Primary Canada signals in title/lead
  let primaryHit = false;
  for (const signal of primaryCanadaSignals) {
    if (title.includes(signal) || lead.includes(signal)) {
      if (!primaryHit) {
        score += 0.5;
        reasons.push('+0.5 primary Canada signal: "' + signal + '"');
        primaryHit = true;
      }
      break;
    }
  }

  // +0.3: Canadian institutions anywhere in content
  let institutionHit = false;
  for (const inst of canadianInstitutions) {
    if (fullText.includes(inst)) {
      if (!institutionHit) {
        score += 0.3;
        reasons.push('+0.3 Canadian institution: "' + inst + '"');
        institutionHit = true;
      }
      break;
    }
  }

  // +0.2: Canadian location anywhere in content
  let locationHit = false;
  for (const loc of canadianLocations) {
    if (fullText.includes(loc)) {
      if (!locationHit) {
        score += 0.2;
        reasons.push('+0.2 Canadian location: "' + loc + '"');
        locationHit = true;
      }
      break;
    }
  }

  // -0.5: Clear foreign focus in title/lead
  let foreignHit = false;
  for (const signal of foreignFocusSignals) {
    if (title.includes(signal) || lead.includes(signal)) {
      if (!foreignHit) {
        score -= 0.5;
        reasons.push('-0.5 foreign focus: "' + signal + '"');
        foreignHit = true;
      }
      break;
    }
  }

  // -0.3: Global topic, no Canada angle (only if no positive signals)
  if (!primaryHit && !institutionHit && !locationHit) {
    for (const signal of globalNoCanadaSignals) {
      if (fullText.includes(signal)) {
        score -= 0.3;
        reasons.push('-0.3 global, no Canada angle: "' + signal + '"');
        break;
      }
    }
  }

  const pass = score >= SCORE_THRESHOLD;
  return { score: Math.round(score * 100) / 100, reasons, pass };
}

// Date formatter
const monthNames = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
function formatPubDate(isoDate) {
  if (!isoDate) return '';
  const date = new Date(isoDate);
  if (isNaN(date.getTime())) return '';
  const month = monthNames[date.getMonth()];
  const day = date.getDate();
  const year = date.getFullYear();
  const hours = String(date.getHours()).padStart(2, '0');
  const minutes = String(date.getMinutes()).padStart(2, '0');
  return month + ' ' + day + ', ' + year + ' @ ' + hours + ':' + minutes;
}

// --- MAIN PIPELINE ---

// 1. Score all items
let scored = $input.all().map(item => {
  const result = scoreArticle(item);
  return { item, score: result.score, reasons: result.reasons, pass: result.pass };
});

// 2. Filter by threshold
let filtered = scored.filter(s => s.pass);

// 3. Deduplicate by URL
const seenLinks = new Set();
filtered = filtered.filter(s => {
  const link = s.item.json.link;
  if (!link || seenLinks.has(link)) return false;
  seenLinks.add(link);
  return true;
});

// 4. Sort LATEST first
filtered.sort((a, b) => {
  const ta = new Date(a.item.json.pubDate).getTime() || 0;
  const tb = new Date(b.item.json.pubDate).getTime() || 0;
  return tb - ta;
});

// 5. Take top 10
let top10 = filtered.slice(0, 10);

// 6. Re-sort EARLIEST first for sheet append order
top10.sort((a, b) => {
  const ta = new Date(a.item.json.pubDate).getTime() || 0;
  const tb = new Date(b.item.json.pubDate).getTime() || 0;
  return ta - tb;
});

// 7. Return — canada_score and score_reasons are extra fields
// Google Sheets node only maps TITLE/DATE/URL/CONTENT so extras are harmless
// Add CANADA SCORE and SCORE REASONS columns to sheet manually to use for QA
return top10.map(s => ({
  json: {
    title: s.item.json.title,
    link: s.item.json.link,
    content: s.item.json.content,
    pubDate: formatPubDate(s.item.json.pubDate),
    canada_score: s.score,
    score_reasons: s.reasons.join(' | ')
  }
}));

// Extract article links from CFIB /en/media page
// CFIB uses HubSpot CMS - articles listed at /en/media/[slug]
try {
  const response = $input.first().json;
  const html = response.data || response.body || '';

  if (!html || html.length < 500) {
    return [];
  }

  const seen = new Set();
  const results = [];

  // Match article links + inline title text
  // Pattern: <a href="/en/media/slug">Article Title</a>
  const articleRegex = /<a[^>]+href="(\/en\/media\/[a-z][a-z0-9\-]{5,})"[^>]*>([^<]{20,300})<\/a>/gi;

  let match;
  while ((match = articleRegex.exec(html)) !== null) {
    const path = match[1];
    const rawTitle = match[2].trim().replace(/\s+/g, ' ');

    if (seen.has(path)) continue;

    // Skip navigation/utility text
    const skipPhrases = ['read more', 'learn more', 'click here', 'view all', 'see all', 'back to', 'filter', 'menu', 'search'];
    if (skipPhrases.some(p => rawTitle.toLowerCase().includes(p))) continue;

    seen.add(path);

    results.push({
      json: {
        title: rawTitle,
        link: 'https://www.cfib-fcei.ca' + path,
        // Use title as content for scoring — P3+P4+P5 fetches full article text
        content: rawTitle,
        pubDate: new Date().toISOString()
      }
    });

    if (results.length >= 10) break;
  }

  // Fallback: slug-only extraction if title regex missed everything
  if (results.length === 0) {
    const slugRegex = /href="(\/en\/media\/[a-z][a-z0-9\-]{15,})"/gi;
    while ((match = slugRegex.exec(html)) !== null) {
      const path = match[1];
      if (seen.has(path)) continue;
      seen.add(path);

      const title = path.split('/').pop().replace(/-/g, ' ').replace(/\b\w/g, l => l.toUpperCase());

      results.push({
        json: {
          title: title,
          link: 'https://www.cfib-fcei.ca' + path,
          content: title,
          pubDate: new Date().toISOString()
        }
      });

      if (results.length >= 10) break;
    }
  }

  return results;
} catch (e) {
  // Return empty — workflow continues with La Presse only
  return [];
}
